SET client_encoding TO 'UTF8';

SET check_function_bodies = false;

CREATE OR REPLACE VIEW vr_nsk_015_002000 (memname, membership_no, salary_amount, member_group_name, loan_requestment_no, loan_request_amount, loan_approve_amount, loan_contract_no, appove_officer, first_install, first_period, begining_of_contract, loan_payment_type_desc, start_keep_date, total_old_loan, total_oldint, buy_share, fee_amount, real_recieve, receipt_no, entry_id, loan_objective_description, bank_acc_no, bank_name, total_share_value, loan_type, loan_type_description) AS SELECT  pka_com_function.fp_get_member_name( sc_mem_m_membership_registered.membership_no  ) as memname,
         sc_mem_m_membership_registered.membership_no,   
         sc_lon_m_loan_request.salary_amount,   
         sc_mem_m_ucf_member_group.member_group_name,   
         sc_lon_m_loan_request.loan_requestment_no,
         sc_lon_m_loan_request.loan_request_amount,   
         sc_lon_m_contract.loan_approve_amount,   
         sc_lon_m_contract.loan_contract_no,   
         sc_lon_m_contract.appove_officer,   
         sc_lon_m_contract.first_install,   
         sc_lon_m_contract.first_period,   
         sc_lon_m_contract.begining_of_contract,            
         sc_lon_m_ucf_loan_payment_type.loan_payment_type_desc,
         sc_lon_m_contract.start_keep_date,   
         sc_lon_m_loan_request.total_old_loan,   
         sc_lon_m_loan_request.total_oldint,   
         sc_lon_m_loan_request.buy_share,   
         sc_lon_m_loan_request.fee_amount,   
         sc_lon_m_contract.real_recieve,            
         (  select receipt_no 
            FROM sc_com_m_receipt 
            where receipt_status = '0' 
            and sc_com_m_receipt.loan_contract_no = sc_lon_m_contract.loan_contract_no) as receipt_no,
         sc_lon_m_loan_request.entry_id,   
         sc_lon_m_ucf_loan_obj.loan_objective_description,   

         (  select max( sc_lon_m_contract_multi_paid.bank_acc_no )
            from sc_lon_m_contract_multi_paid
            where (sc_lon_m_contract_multi_paid.bank_acc_no IS NOT NULL AND sc_lon_m_contract_multi_paid.bank_acc_no::text <> '')
            and sc_lon_m_contract_multi_paid.loan_contract_no = sc_lon_m_contract.loan_contract_no  
         ) as bank_acc_no ,

         (  select  CASE WHEN  sc_lon_m_contract_multi_paid.type_pay_money ='TRD' THEN  'Coop' 							  ELSE ( select sc_acc_m_ucf_bank.short_name from  sc_acc_m_ucf_bank where  sc_acc_m_ucf_bank.bank_id = sc_lon_m_contract_multi_paid.bank_code ) END 
            from sc_lon_m_contract_multi_paid          
            where 1=1           
            and sc_lon_m_contract_multi_paid.loan_contract_no = sc_lon_m_contract.loan_contract_no
            and sc_lon_m_contract_multi_paid.bank_acc_no = ( select max( sc_lon_m_contract_multi_paid.bank_acc_no )
                                from sc_lon_m_contract_multi_paid
                                where (sc_lon_m_contract_multi_paid.bank_acc_no IS NOT NULL AND sc_lon_m_contract_multi_paid.bank_acc_no::text <> '')
                                and sc_lon_m_contract_multi_paid.loan_contract_no = sc_lon_m_contract.loan_contract_no 
                                ) 
          ) as bank_name ,
         sc_lon_m_loan_request.total_share_value ,
         sc_lon_m_rule.loan_type ,
         sc_lon_m_rule.loan_type_description
    FROM sc_mem_m_membership_registered,  
         sc_mem_m_ucf_member_group,   
         sc_lon_m_loan_request,   
         sc_lon_m_contract,   
         sc_lon_m_ucf_loan_obj,
         sc_lon_m_ucf_loan_payment_type ,
         sc_lon_m_rule
   WHERE ( sc_lon_m_rule.loan_type = sc_lon_m_contract.loan_type) and (sc_lon_m_ucf_loan_payment_type.loan_payment_type_code = sc_lon_m_contract.first_paytype ) and ( sc_mem_m_membership_registered.member_group_no = sc_mem_m_ucf_member_group.member_group_no ) and ( sc_lon_m_loan_request.loan_requestment_no = sc_lon_m_contract.loan_requestment_no ) and ( sc_lon_m_contract.membership_no = sc_mem_m_membership_registered.membership_no ) and ( sc_lon_m_contract.loan_type = sc_lon_m_ucf_loan_obj.loan_type ) and ( sc_lon_m_contract.loan_objective_code = sc_lon_m_ucf_loan_obj.loan_objective_code ) and ( sc_lon_m_rule.invest_status = '0' ) 
         --and ( sc_lon_m_contract.begining_of_contract >= '1/1/2024' ) 
 
  ORDER BY sc_lon_m_contract.begining_of_contract , sc_lon_m_contract.loan_contract_no;

